97	                                parseHtmlToAnnotatedString(block.html, linkColor, mentionBg, codeBg)
98	                            }
99	                            if (annotatedString.isNotEmpty()) {
100	                                ClickableText(
101	                                    text = annotatedString,
102	                                    style = bodyStyle,
103	                                    onClick = { offset ->
104	                                        handleClick(annotatedString, offset, uriHandler, onMentionClick, onLinkClick, onTextClick)
105	                                    }
106	                                )
107	                            }
108	                        }
109	                    }
