123	private fun handleClick(
124	    annotatedString: AnnotatedString,
125	    offset: Int,
126	    uriHandler: androidx.compose.ui.platform.UriHandler,
127	    onMentionClick: ((String) -> Unit)?,
128	    onLinkClick: ((String) -> Unit)?,
129	    onTextClick: (() -> Unit)? = null
130	) {
131	    annotatedString.getStringAnnotations("MENTION", offset, offset)
132	        .firstOrNull()?.let { annotation ->
133	            val handle = extractHandleFromUrl(annotation.item)
134	            if (handle != null && onMentionClick != null) {
135	                onMentionClick(handle)
136	            } else {
137	                try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
138	            }
139	            return
140	        }
141	
142	    annotatedString.getStringAnnotations("URL", offset, offset)
143	        .firstOrNull()?.let { annotation ->
144	            if (onLinkClick != null) {
145	                onLinkClick(annotation.item)
146	            } else {
147	                try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
