156	private fun splitIntoBlocks(html: String): List<ContentBlock> {
157	    val blocks = mutableListOf<ContentBlock>()
158	    var lastEnd = 0
159	    val source = html.trim()
160	
161	    for (match in PRE_CODE_REGEX.findAll(source)) {
162	        val before = source.substring(lastEnd, match.range.first)
163	        if (before.isNotBlank()) {
164	            blocks.add(ContentBlock.Text(before))
165	        }
166	
167	        val codeHtml = match.groupValues[1]
168	        blocks.add(ContentBlock.Code(codeHtml))
169	
170	        lastEnd = match.range.last + 1
171	    }
172	
173	    val after = source.substring(lastEnd)
174	    if (after.isNotBlank()) {
175	        blocks.add(ContentBlock.Text(after))
176	    }
177	
178	    // If no code blocks found, return the whole thing as text
179	    if (blocks.isEmpty()) {
180	        blocks.add(ContentBlock.Text(source))
181	    }
182	
183	    return blocks
184	}
