186	private fun extractHandleFromUrl(url: String): String? {
187	    return try {
188	        val uri = URI(url)
189	        val host = uri.host ?: return null
190	        val path = uri.path ?: return null
191	        val username = path.trimStart('/').removePrefix("@")
192	        if (username.isNotEmpty()) "$username@$host" else null
193	    } catch (_: Exception) {
194	        null
195	    }
196	}
