198	private fun parseHtmlToAnnotatedString(
199	    html: String,
200	    linkColor: Color,
201	    mentionBg: Color,
202	    codeBg: Color
203	): AnnotatedString {
204	    return buildAnnotatedString {
205	        // Link state
206	        var currentLinkType: LinkType? = null
207	        var hasAnnotation = false
208	
209	        // Invisible span state
210	        var insideInvisibleSpan = false
211	        var invisibleSpanDepth = 0
212	
213	        // Inline style depths (for push/pop tracking)
214	        var boldDepth = 0
215	        var italicDepth = 0
216	        var codeDepth = 0
217	        var strikeDepth = 0
218	
219	        // Block state
220	        var preDepth = 0
221	        var headingLevel = 0
222	        var blockquoteDepth = 0
223	
224	        // List state
225	        val listStack = mutableListOf<ListContext>()
226	        var insideListItem = false
227	
228	        var hasContent = false
229	        var pos = 0
230	        val source = html.trim()
231	
232	        while (pos < source.length) {
233	            val tagMatch = TAG_REGEX.find(source, pos)
234	
235	            // Text before the next tag (or remaining text)
236	            if (tagMatch == null || tagMatch.range.first > pos) {
237	                val textEnd = tagMatch?.range?.first ?: source.length
238	                val rawText = source.substring(pos, textEnd)
239	                val decoded = decodeHtmlEntities(rawText)
240	
241	                if (!insideInvisibleSpan && decoded.isNotEmpty()) {
242	                    if (preDepth > 0) {
243	                        // Preserve all whitespace in preformatted blocks
244	                        appendStyledText(this, decoded, currentLinkType, linkColor, mentionBg)
245	                        hasContent = true
246	                    } else {
247	                        val isInterBlockWhitespace = decoded.isBlank() && decoded.contains('\n')
248	                        if (!isInterBlockWhitespace) {
249	                            appendStyledText(this, decoded, currentLinkType, linkColor, mentionBg)
250	                            hasContent = true
251	                        }
252	                    }
253	                }
254	
255	                pos = textEnd
256	            }
257	
258	            if (tagMatch != null && tagMatch.range.first == pos) {
259	                val isClosing = tagMatch.groupValues[1] == "/"
260	                val tagName = tagMatch.groupValues[2].lowercase()
261	                val attrString = tagMatch.groupValues[3]
262	
263	                if (!isClosing) {
264	                    val attrs = parseAttributes(attrString)
265	
266	                    when (tagName) {
267	                        // Block elements
268	                        "p" -> {
269	                            if (hasContent) append("\n\n")
270	                        }
271	                        "br" -> {
272	                            append("\n")
273	                        }
274	
275	                        // Headings
276	                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
277	                            headingLevel = tagName[1].digitToInt()
278	                            if (hasContent) append("\n\n")
279	                            val fontSize = when (headingLevel) {
280	                                1 -> 1.5.em
281	                                2 -> 1.3.em
282	                                3 -> 1.15.em
283	                                else -> 1.0.em
284	                            }
285	                            pushStyle(SpanStyle(
286	                                fontSize = fontSize,
287	                                fontWeight = FontWeight.Bold
288	                            ))
289	                        }
290	
291	                        // Preformatted / code blocks
292	                        "pre" -> {
293	                            if (hasContent) append("\n\n")
294	                            preDepth++
295	                            pushStyle(SpanStyle(
296	                                fontFamily = FontFamily.Monospace,
297	                                background = codeBg,
298	                                fontSize = 0.875.em
299	                            ))
300	                        }
301	
302	                        // Inline code
303	                        "code" -> {
304	                            codeDepth++
305	                            if (preDepth == 0) {
306	                                // Only style inline <code>, not <pre><code>
307	                                pushStyle(SpanStyle(
308	                                    fontFamily = FontFamily.Monospace,
309	                                    background = codeBg,
310	                                    fontSize = 0.875.em
311	                                ))
312	                            }
313	                        }
314	
315	                        // Bold
316	                        "strong", "b" -> {
317	                            boldDepth++
318	                            pushStyle(SpanStyle(fontWeight = FontWeight.Bold))
319	                        }
320	
321	                        // Italic
322	                        "em", "i" -> {
323	                            italicDepth++
324	                            pushStyle(SpanStyle(fontStyle = FontStyle.Italic))
325	                        }
326	
327	                        // Strikethrough
328	                        "del", "s" -> {
329	                            strikeDepth++
330	                            pushStyle(SpanStyle(textDecoration = TextDecoration.LineThrough))
331	                        }
332	
333	                        // Horizontal rule
334	                        "hr" -> {
335	                            if (hasContent) append("\n")
336	                            append("\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500")
337	                            append("\n")
338	                            hasContent = true
339	                        }
340	
341	                        // Blockquote
342	                        "blockquote" -> {
343	                            if (hasContent) append("\n\n")
344	                            blockquoteDepth++
345	                            pushStyle(SpanStyle(
346	                                fontStyle = FontStyle.Italic,
347	                                color = Color(0xFF6B7280)
348	                            ))
349	                        }
350	
351	                        // Lists
352	                        "ul" -> {
353	                            if (hasContent && listStack.isEmpty()) append("\n")
354	                            listStack.add(ListContext(ordered = false))
355	                        }
356	                        "ol" -> {
357	                            if (hasContent && listStack.isEmpty()) append("\n")
358	                            listStack.add(ListContext(ordered = true))
359	                        }
360	                        "li" -> {
361	                            if (insideListItem) append("\n")
362	                            val ctx = listStack.lastOrNull()
363	                            val indent = "  ".repeat((listStack.size - 1).coerceAtLeast(0))
364	                            if (ctx != null) {
365	                                if (ctx.ordered) {
366	                                    ctx.itemIndex++
367	                                    append("${indent}${ctx.itemIndex}. ")
368	                                } else {
369	                                    append("${indent}\u2022 ")
370	                                }
371	                            }
372	                            insideListItem = true
373	                            hasContent = true
374	                        }
375	
376	                        // Links
377	                        "a" -> {
378	                            val classes = attrs["class"] ?: ""
379	                            val href = attrs["href"] ?: ""
380	
381	                            currentLinkType = when {
382	                                "hashtag" in classes -> LinkType.HASHTAG
383	                                "mention" in classes -> LinkType.MENTION
384	                                href.isNotEmpty() -> LinkType.REGULAR
385	                                else -> null
386	                            }
387	
388	                            if (href.isNotEmpty()) {
389	                                val tag = if (currentLinkType == LinkType.MENTION) "MENTION" else "URL"
390	                                pushStringAnnotation(tag, href)
391	                                hasAnnotation = true
392	                            }
393	                        }
394	
395	                        // Invisible spans
396	                        "span" -> {
397	                            val classes = attrs["class"] ?: ""
398	                            if ("invisible" in classes) {
399	                                insideInvisibleSpan = true
400	                                invisibleSpanDepth++
401	                            }
402	                        }
403	                    }
404	                } else {
405	                    // Closing tags
406	                    when (tagName) {
407	                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
408	                            if (headingLevel > 0) {
409	                                pop()
410	                                headingLevel = 0
411	                            }
412	                        }
413	
414	                        "pre" -> {
415	                            if (preDepth > 0) {
416	                                preDepth--
417	                                pop()
418	                            }
419	                        }
420	
421	                        "code" -> {
422	                            if (codeDepth > 0) {
423	                                codeDepth--
424	                                if (preDepth == 0) {
425	                                    // Only pop if we pushed for inline code
426	                                    pop()
427	                                }
428	                            }
429	                        }
430	
431	                        "strong", "b" -> {
432	                            if (boldDepth > 0) {
433	                                boldDepth--
434	                                pop()
435	                            }
436	                        }
437	
438	                        "em", "i" -> {
439	                            if (italicDepth > 0) {
440	                                italicDepth--
441	                                pop()
442	                            }
443	                        }
444	
445	                        "del", "s" -> {
446	                            if (strikeDepth > 0) {
447	                                strikeDepth--
448	                                pop()
449	                            }
450	                        }
451	
452	                        "blockquote" -> {
453	                            if (blockquoteDepth > 0) {
454	                                blockquoteDepth--
455	                                pop()
456	                            }
457	                        }
458	
459	                        "ul", "ol" -> {
460	                            if (listStack.isNotEmpty()) {
461	                                listStack.removeLast()
462	                            }
463	                            insideListItem = false
464	                            if (listStack.isEmpty() && hasContent) {
465	                                append("\n")
466	                            }
467	                        }
468	
469	                        "li" -> {
470	                            // Keep insideListItem = true so next <li> adds a newline
471	                        }
472	
473	                        "a" -> {
474	                            if (hasAnnotation) {
475	                                pop()
476	                                hasAnnotation = false
477	                            }
478	                            currentLinkType = null
479	                        }
480	
481	                        "span" -> {
482	                            if (insideInvisibleSpan) {
483	                                invisibleSpanDepth--
484	                                if (invisibleSpanDepth <= 0) {
485	                                    insideInvisibleSpan = false
486	                                    invisibleSpanDepth = 0
487	                                }
488	                            }
489	                        }
490	                    }
491	                }
492	
493	                pos = tagMatch.range.last + 1
494	            }
495	        }
496	    }
497	}
498	
499	private fun appendStyledText(
500	    builder: AnnotatedString.Builder,
501	    text: String,
502	    linkType: LinkType?,
503	    linkColor: Color,
504	    mentionBg: Color
505	) {
506	    when (linkType) {
507	        LinkType.MENTION -> {
508	            builder.withStyle(
509	                SpanStyle(
510	                    color = linkColor,
511	                    fontWeight = FontWeight.SemiBold,
512	                    background = mentionBg
513	                )
514	            ) {
515	                append(text)
516	            }
517	        }
518	        LinkType.HASHTAG -> {
519	            builder.withStyle(SpanStyle(color = linkColor)) {
520	                append(text)
521	            }
522	        }
523	        LinkType.REGULAR -> {
524	            builder.withStyle(
525	                SpanStyle(
526	                    color = linkColor,
527	                    textDecoration = TextDecoration.Underline
528	                )
529	            ) {
530	                append(text)
531	            }
532	        }
533	        null -> {
534	            builder.append(text)
535	        }
536	    }
537	}
538	
539	private fun parseAttributes(attrString: String): Map<String, String> {
540	    val attrs = mutableMapOf<String, String>()
541	    for (match in ATTR_REGEX.findAll(attrString)) {
542	        attrs[match.groupValues[1]] = match.groupValues[2]
543	    }
544	    return attrs
545	}
546	
547	private fun decodeHtmlEntities(text: String): String {
548	    return text
549	        .replace("&nbsp;", " ")
550	        .replace("&amp;", "&")
551	        .replace("&lt;", "<")
552	        .replace("&gt;", ">")
553	        .replace("&quot;", "\"")
554	        .replace("&#39;", "'")
555	        .replace("&apos;", "'")
556	}
