    bottomBar = {
        if (showBottomBar) {
            BottomNavBar(
                items = bottomNavItems,
                selectedRoute = currentBaseRoute ?: "",
                onItemSelected = { item ->
                    navController.navigate(item.route) {
                        popUpTo(navController.graph.findStartDestination().id) {
                            saveState = true
                        }
                        launchSingleTop = true
                        restoreState = true
                    }
